import * as connect from 'connect';
import * as https from 'https';
import * as http from 'http';
import Router = require('router');
import {EventEmitter} from 'events';
import {PromiseUtils} from 'jibo-cai-utils';

import parentLog from '../log';
const log = parentLog.createChild('HTTPSTLSService');

const prify = PromiseUtils.promisify;

export interface ServiceOptions {
    port: number;
    key: string | Buffer;
    cert: string | Buffer;
    ca?: string | Buffer;  // prob not needed
}


export class HTTPSTLSService extends EventEmitter {

    app: connect.Server;
    server: https.Server;
    staticDir: string;
    router: Router;
    name: string;
    options: ServiceOptions;
    rootDir: string;

    private static get _onRobot(): boolean {
        // Check environment variables for run mode
        let runMode: string = process.env.runMode || process.env.RUNMODE;
        // Default to ON_ROBOT under arm/linux if not set
        if (!runMode && process.platform === 'linux' && process.arch === 'arm') {
            runMode = 'ON_ROBOT';
        }
        return runMode === 'ON_ROBOT';
    }


    constructor(name: string, options: ServiceOptions) {
        super();
        this.name = name;
        this.options = options;
    }


    init(callback: (err?: Error) => void) {
        this.app = connect();
        this.router = new Router();
        this.routes(<Router>this.router);
        (<any>this.app).use(this.router);


        const httpsOptions = {
            key: this.options.key,
            cert: this.options.cert,
            ca: this.options.ca,  // this one is prob not needed
            requestCert: true,
            //rejectUnauthorized: true,  // we don't want to check the certificate signing, we use the fingerprint instead
        };
        this.server = https.createServer(httpsOptions, this.app);

        // we are not going to do this for the security controller,
        // port 7160 or die.
        // HTTPSTLSService.getPort(this.options.port)
        // .catch((err: Error) => {
        //     log.error(err.message);
        //     throw err;
        // })
        Promise.resolve(this.options.port)
        .then(port => {
            if(this.options.port !== 0 && this.options.port !== port) {
                log.warn(`Requested port ${this.options.port} unavailable; listening on ${port} instead`);
            }
            // We pass the hostname of 127.0.0.1 explicitly here off-robot
            // so we don't get a success code if a port is already bound only
            // to localhost, but not to another available interface, which is
            // the default (0.0.0.0)
            // We don't need to discern which mode we're in or whether the
            // service should be available outside the bot, since we have
            // a firewall for that.
            //const hostname = HTTPSTLSService._onRobot ? '0.0.0.0' : '127.0.0.1';
            const hostname = '0.0.0.0';  // allows rom apps to use the simulator
            return prify(cb => this.server.listen(port, hostname, cb))
                .then(() => {
                    this.emit('serverStartup');
                    this.port = this.server.address().port;
                })
                .catch(err => {
                    log.error(`Can't listen on port ${this.options.port}`, err);
                    throw err;
                });
        })
        .then(() => {
            log.info(`${this.name} service listening on port ${this.options.port}`);
            callback();
        })
        .catch(err => callback(err));
    }


    close() {
        this.server.close();
    }


    get port():number {
        return this.options.port ? this.options.port : 0;
    }


    set port(value:number) {
        this.options.port = value;
    }


    routes(url:Router):void {
        //we are not registering with the registry
        // url.get('/_M_/errors', this.onErrors.bind(this));
        // url.get('/_M_/health', this.onHealth.bind(this));
        // url.post('/_M_/system/backup', this.onBackupRequest.bind(this));
        // url.post('/_M_/system/restore', this.onRestoreRequest.bind(this));
        // url.post('/_M_/system/wipe', this.onWipeRequest.bind(this));
    }


    finish(
        res: http.ServerResponse,
        err?: Error | string,
        data?: any,
        contentType?: string,
        statusCode: number = 200,
    ): void {
        if (err) {
            const body = err.toString();
            res.setHeader('Content-Type', 'text/plain');
            res.setHeader('Content-Length', Buffer.byteLength(body).toString());
            res.statusCode =
                !statusCode || statusCode === 200 ? 500 : statusCode;
            return res.end(body);
        }
        // enforce no content on 204, and 204 when no content
        if (statusCode === 204 || !data) {
            res.statusCode = 204;
            res.setHeader('Content-Length', '0');
            return res.end();
        }
        if (contentType) {
            // http://stackoverflow.com/questions/24729329/node-js-how-to-disable-chunked-transfer-encoding
            //res.removeHeader('Transfer-Encoding');
            res.setHeader('Content-Type', contentType);
        }
        res.setHeader('Content-Length', Buffer.byteLength(data).toString());
        res.statusCode = statusCode < 1 ? 200 : statusCode;
        res.end(data);
    }


    finishNoContent(
        res: http.ServerResponse,
        status?: number,
        err?: Error | string,
    ) {
        this.finish(res, err, null, null, 204);
    }


    sendJson(
        res: http.ServerResponse,
        json: Object|string,
        statusCode: number = 200
    ): void {
        let err;
        if (typeof json !== 'string') {
            try {
                json = JSON.stringify(json);
            } catch (e) {
                log.error('JSON.stringify: ', e);
                json = null;
                err = e;
            }
        }
        this.finish(res, err, json, 'application/json', statusCode);
    }


    destroy(callback?: (err?: Error|string)=>void): void {
        if ((<any>this.server).listening) {   // .listening was added in node v5.7.0
            this.server.close(callback);
        }
        else {
            if(callback) {
                callback();
            }
        }
    }
}
