import {EventEmitter} from 'events';
// import {RegistryClient} from 'jibo-service-framework';
// import {SystemManagerClient} from 'jibo-client-framework';
import SecurityControllerService from '../../services/security-controller/SecurityControllerService';
import {instantiateService} from '../../SSMService';

import parentLog from '../../services/log';
const log = parentLog.createChild('SCS');


class SCSProcess extends EventEmitter {

    constructor() {
        super();

        // process.on('SIGINT', function(event) {
        //     log.debug("Caught interrupt signal");
        //     setTimeout(() => {
        //         log.debug('REALLY EXIT');
        //         process.exit();
        //     }, 5000);
        // });

        instantiateService(SecurityControllerService);
        SecurityControllerService.instance.init( (err) => {
            log.iferr(err, 'error initing SecurityControllerService');

            let sem = require('node-semaphore');
            log.debug('SEMAPHORE', 'pid', process.pid);
            let s = sem.Semaphore('/jibo-startup-' + process.pid + '.event');
            s.post();

            log.info('SCS Started');
        });
    }
}

export default function() {
    return new SCSProcess();
}
